module top_module(
  input [11:0] MUX_I,
  input [3:0] S,
  output reg O
);always @ (S or MUX_I) begin
    case(S)
      4'd0: O = MUX_I[0];
      4'd1: O = MUX_I[1];
      4'd2: O = MUX_I[2];
      4'd3: O = MUX_I[3];
      4'd4: O = MUX_I[4];
      4'd5: O = MUX_I[5];
      4'd6: O = MUX_I[6];
      4'd7: O = MUX_I[7];
      4'd8: O = MUX_I[8];
      4'd9: O = MUX_I[9];
      4'd10: O = MUX_I[10];
      4'd11: O = MUX_I[11];
      default: O = 1'b0;
    endcase
  end

endmodule
